output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?archon ?label ?nativeLabel WHERE {
  ?archon wdt:P140 wd:Q48420 .
  OPTIONAL {
    ?archon rdfs:label ?label .
    FILTER(lang(?label) = 'en')
  }
  OPTIONAL {
    ?archon wdt:P1705 ?nativeLabel
  }
  VALUES ?archon {
    wd:Q2603125 wd:Q97358258 wd:Q1193956
  }
}
ORDER BY ?archon

args.sparql:
SELECT ?archon ?archonLabel ?origin WHERE {
  ?archon wdt:P140 wd:Q48420;
          wdt:P31/wdt:P279* wd:Q183488.
  OPTIONAL { ?archon rdfs:label ?archonLabel. FILTER(lang(?archonLabel) = 'en') }
  OPTIONAL { ?archon wdt:P1705 ?nativeLabel }
  BIND(IF(BOUND(?nativeLabel), CONCAT('Origin likely from Greek/Hebrew roots based on transliteration: ', ?nativeLabel), 'Origin not directly stated in Wikidata') AS ?origin)
}
LIMIT 7

SELECT DISTINCT ?archon ?label ?nativeLabel WHERE {
  ?archon wdt:P140 wd:Q48420.
  OPTIONAL { ?archon rdfs:label ?label. FILTER(lang(?label) = 'en') }
  OPTIONAL { ?archon wdt:P1705 ?nativeLabel }
  VALUES ?archon { wd:Q2603125 wd:Q97358258 wd:Q1193956 }
}
ORDER BY ?archon
